mapper.select:
select customer_id as dimension_id, sum(case when datediff(curdate(), due_date) < 0 then amount - received_amount else 0 end) as not_due_amount, sum(case when datediff(curdate(), due_date) between 0 and 30 then amount - received_amount else 0 end) as days_0_30_amount, sum(case when datediff(curdate(), due_date) between 31 and 60 then amount - received_amount else 0 end) as days_31_60_amount, sum(case when datediff(curdate(), due_date) between 61 and 90 then amount - received_amount else 0 end) as days_61_90_amount, sum(case when datediff(curdate(), due_date) > 90 then amount - received_amount else 0 end) as days_90_above_amount from fin_receivable
and customer_id = #{customerId}
group by customer_id

select supplier_id as dimension_id, sum(case when datediff(curdate(), due_date) < 0 then amount - paid_amount else 0 end) as not_due_amount, sum(case when datediff(curdate(), due_date) between 0 and 30 then amount - paid_amount else 0 end) as days_0_30_amount, sum(case when datediff(curdate(), due_date) between 31 and 60 then amount - paid_amount else 0 end) as days_31_60_amount, sum(case when datediff(curdate(), due_date) between 61 and 90 then amount - paid_amount else 0 end) as days_61_90_amount, sum(case when datediff(curdate(), due_date) > 90 then amount - paid_amount else 0 end) as days_90_above_amount from fin_payable
and supplier_id = #{supplierId}
group by supplier_id

select customer_id as dimension_id, sum(amount) as bill_amount, sum(received_amount) as paid_amount, sum(amount - received_amount) as diff_amount from fin_receivable
and customer_id = #{customerId}
group by customer_id

select supplier_id as dimension_id, sum(amount) as bill_amount, sum(paid_amount) as paid_amount, sum(amount - paid_amount) as diff_amount from fin_payable
and supplier_id = #{supplierId}
group by supplier_id
